const matcherProfiles = [{"id":"cs","math":28,"weights":{"fm":28,"physics":12,"chemistry":4,"economics":5,"biology":3,"psychology":3,"business":2},"essential":[],"recommended":["fm"],"synergies":[[["fm","physics"],7]],"note":{"zh":"数学是核心；如果学校开设 Further Mathematics，申请顶尖计算机项目时通常很有帮助。没有计算机A-Level并不妨碍申请，但要用项目证明你确实理解算法和系统。","en":"Mathematics is central. Further Mathematics is often valuable for highly selective computing courses when available. A Computer Science A level is not essential, but projects should show real understanding of algorithms and systems."},"study":[{"zh":"把函数、数列、概率和图论题写成完整推导，不只记录答案。","en":"Write complete reasoning for functions, sequences, probability and graph problems rather than recording answers only."},{"zh":"用Python实现数据结构、搜索、动态规划或简单网络程序，并比较不同算法的效率。","en":"Use Python to implement data structures, search, dynamic programming or a small networked application, then compare algorithmic efficiency."},{"zh":"每个项目保留问题定义、测试、失败记录和改进过程。","en":"Keep the problem definition, tests, failures and iterations for every project."}],"epq":[{"zh":"生成式AI写出的代码，在哪些类型的任务上最容易出错？","en":"On which types of task is code generated by generative AI most likely to fail?"},{"zh":"不同路径规划算法在拥堵或不完整信息下如何表现？","en":"How do path-planning algorithms behave under congestion or incomplete information?"},{"zh":"自动决策系统应在准确率和可解释性之间怎样取舍？","en":"How should automated decision systems balance accuracy and explainability?"},{"zh":"更严格的密码规则真的能提高安全性，还是会让用户寻找绕过办法？","en":"Do stricter password rules genuinely improve security, or encourage users to work around them?"}],"courses":[{"name":"MIT OCW: Introduction to Computer Science and Programming in Python","url":"https://ocw.mit.edu/courses/6-0001-introduction-to-computer-science-and-programming-in-python-fall-2016/"},{"name":"Isaac Computer Science","url":"https://isaaccomputerscience.org/"},{"name":"Harvard CS50x","url":"https://cs50.harvard.edu/x/"},{"name":"University of Helsinki MOOC.fi Programming Courses","url":"https://www.mooc.fi/en/courses/"}],"books":[{"zh":"Code: The Hidden Language of Computer Hardware and Software — Charles Petzold","en":"Code: The Hidden Language of Computer Hardware and Software — Charles Petzold"},{"zh":"The Algorithm Design Manual — Steven Skiena（选读章节）","en":"The Algorithm Design Manual — Steven Skiena (selected chapters)"},{"zh":"Computer Systems: A Programmer’s Perspective — Randal Bryant & David O’Hallaron（选读）","en":"Computer Systems: A Programmer’s Perspective — Randal Bryant & David O’Hallaron (selected chapters)"},{"zh":"Algorithms to Live By — Brian Christian & Tom Griffiths","en":"Algorithms to Live By — Brian Christian & Tom Griffiths"}],"summer":[{"name":"Cambridge Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"Imperial Global Summer School / high-school computing programmes","url":"https://www.imperial.ac.uk/study/visit/summer-schools/high-school/"}],"ceiling":98,"portfolio":false},{"id":"visual","math":8,"weights":{"fm":2,"physics":4,"chemistry":2,"economics":8,"biology":3,"psychology":18,"business":12},"essential":[],"recommended":["psychology","business"],"synergies":[[["psychology","business"],5]],"note":{"zh":"课程组合只能反映一部分准备度；视觉传达最关键的仍是作品集、观察力和对受众的理解。没有Art或Design A-Level时，更要主动建立作品集。","en":"Subject choices show only part of your preparation. Portfolio quality, observation and audience understanding are decisive. Without an Art or Design A level, you need to build a portfolio independently."},"study":[{"zh":"练习信息层级、字体、色彩、版式和叙事，不要只追求“好看”。","en":"Practise information hierarchy, typography, colour, layout and narrative rather than aiming only for attractive outcomes."},{"zh":"从Psychology学习知觉、注意和用户行为，再把概念放进真实设计测试。","en":"Use Psychology to understand perception, attention and user behaviour, then test those ideas in real designs."},{"zh":"每个作品写清楚对象、问题、研究、迭代和取舍。","en":"For every piece, explain the audience, problem, research, iteration and trade-offs."}],"epq":[{"zh":"同一公共信息用不同视觉层级呈现，会怎样影响理解和行动？","en":"How does changing visual hierarchy in public information affect comprehension and action?"},{"zh":"短视频封面中的色彩与构图是否会改变点击选择？","en":"Do colour and composition in short-video thumbnails change click choices?"},{"zh":"无障碍设计会限制品牌表达，还是会让视觉系统更清楚？","en":"Does accessible design constrain brand expression, or make a visual system clearer?"},{"zh":"不同的数据可视化方式会怎样改变人们对风险的判断？","en":"How do different data-visualisation choices alter perceptions of risk?"}],"courses":[{"name":"OpenLearn: Understanding your customers","url":"https://www.open.edu/openlearn/money-business/understanding-your-customers/content-section-0?intro=1"},{"name":"Oxford Supercurricular Hub: Art, design and visual resources","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"},{"name":"CalArts Graphic Design Specialization","url":"https://www.coursera.org/specializations/graphic-design"},{"name":"MoMA: Seeing Through Photographs","url":"https://www.coursera.org/learn/photography"}],"books":[{"zh":"The Design of Everyday Things — Don Norman","en":"The Design of Everyday Things — Don Norman"},{"zh":"Ways of Seeing — John Berger","en":"Ways of Seeing — John Berger"},{"zh":"Grid Systems in Graphic Design — Josef Müller-Brockmann","en":"Grid Systems in Graphic Design — Josef Müller-Brockmann"},{"zh":"Don’t Make Me Think — Steve Krug","en":"Don’t Make Me Think — Steve Krug"}],"summer":[{"name":"University-run portfolio or design short courses for ages 16–18","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"},{"name":"Cambridge Subject Masterclasses where relevant","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"}],"ceiling":82,"portfolio":true},{"id":"mech","math":27,"weights":{"fm":22,"physics":30,"chemistry":7,"economics":3,"biology":3,"psychology":2,"business":4},"essential":["physics"],"recommended":["fm"],"synergies":[[["fm","physics"],10],[["physics","chemistry"],3]],"note":{"zh":"大多数机械工程课程把数学和物理视为最直接的准备。Further Mathematics会让力学、微分方程和建模过渡更顺。","en":"Mathematics and Physics are the most direct preparation for Mechanical Engineering. Further Mathematics makes mechanics, differential equations and modelling easier to enter."},"study":[{"zh":"把力学题延伸成模型：先写假设，再比较理论值与实验值。","en":"Turn mechanics problems into models: state assumptions, then compare theory with experiment."},{"zh":"补充微积分、向量、微分方程和误差分析。","en":"Strengthen calculus, vectors, differential equations and error analysis."},{"zh":"学习基础CAD或Python，但重点放在设计取舍和测试。","en":"Learn basic CAD or Python, but focus on design trade-offs and testing."}],"epq":[{"zh":"不同材料和截面如何影响轻量化结构的刚度与安全？","en":"How do material and cross-section choices affect stiffness and safety in lightweight structures?"},{"zh":"小型风力机叶片角度如何影响输出功率？","en":"How does blade angle affect the power output of a small wind turbine?"},{"zh":"小型车辆的再生制动在不同速度和载荷下能回收多少能量？","en":"How much energy can regenerative braking recover in a small vehicle at different speeds and loads?"},{"zh":"3D打印零件与传统加工零件的强度差异主要来自哪里？","en":"What mainly causes the strength difference between 3D-printed and conventionally manufactured parts?"}],"courses":[{"name":"MIT OCW: Classical Mechanics","url":"https://ocw.mit.edu/courses/8-01sc-classical-mechanics-fall-2016/"},{"name":"Coursera: Mechanical Engineering courses","url":"https://www.coursera.org/browse/physical-science-and-engineering/mechanical-engineering"},{"name":"MIT OCW: Engineering Dynamics","url":"https://ocw.mit.edu/courses/2-003sc-engineering-dynamics-fall-2011/"},{"name":"TU Delft: Introduction to Aeronautical Engineering","url":"https://www.edx.org/learn/aeronautical-engineering/delft-university-of-technology-introduction-to-aeronautical-engineering"}],"books":[{"zh":"To Engineer Is Human — Henry Petroski","en":"To Engineer Is Human — Henry Petroski"},{"zh":"Structures: Or Why Things Don’t Fall Down — J. E. Gordon","en":"Structures: Or Why Things Don’t Fall Down — J. E. Gordon"},{"zh":"The New Science of Strong Materials — J. E. Gordon","en":"The New Science of Strong Materials — J. E. Gordon"},{"zh":"How Things Work — Louis A. Bloomfield","en":"How Things Work — Louis A. Bloomfield"}],"summer":[{"name":"Imperial Global Summer School","url":"https://www.imperial.ac.uk/be-inspired/global-summer-school/"},{"name":"Cambridge Engineering Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"}],"ceiling":98,"portfolio":false},{"id":"psych","math":13,"weights":{"fm":6,"physics":3,"chemistry":8,"economics":7,"biology":24,"psychology":28,"business":5},"essential":[],"recommended":["psychology","biology"],"synergies":[[["psychology","biology"],9],[["psychology","fm"],4]],"note":{"zh":"Psychology本身很有帮助，但顶尖课程也重视生物、统计、实验设计和批判性写作。","en":"Psychology is useful, but selective courses also value biology, statistics, experimental design and critical writing."},"study":[{"zh":"把研究方法学扎实：相关不等于因果，样本和量表都会影响结论。","en":"Build strong research-methods habits: correlation is not causation, and samples and measures shape conclusions."},{"zh":"用Biology理解神经、激素和遗传，但不要把心理现象简单还原成生物原因。","en":"Use Biology to understand neural, hormonal and genetic mechanisms without reducing every psychological phenomenon to biology."},{"zh":"阅读研究时记录假设、方法、结果、限制和替代解释。","en":"When reading studies, record hypotheses, methods, results, limitations and alternative explanations."}],"epq":[{"zh":"睡眠时间与青少年注意力之间的关系能否被手机使用解释？","en":"Can phone use explain the relationship between sleep duration and adolescent attention?"},{"zh":"默认选项如何影响学生在校园中的选择？","en":"How do default options influence student choices at school?"},{"zh":"社交媒体使用与青少年自尊之间的关系，有多少证据能支持因果解释？","en":"How much evidence supports a causal link between social-media use and adolescent self-esteem?"},{"zh":"目击者的自信程度能否可靠预测记忆准确性？","en":"Can eyewitness confidence reliably predict memory accuracy?"}],"courses":[{"name":"OpenLearn: Free Psychology courses","url":"https://www.open.edu/openlearn/body-mind/free-courses"},{"name":"Coursera: Introduction to Psychology / research methods","url":"https://www.coursera.org/browse/health/psychology"},{"name":"Yale Open Courses: Introduction to Psychology","url":"https://oyc.yale.edu/psychology/psyc-110"},{"name":"MIT OCW: Introduction to Psychology","url":"https://ocw.mit.edu/courses/9-00sc-introduction-to-psychology-fall-2011/"}],"books":[{"zh":"Thinking, Fast and Slow — Daniel Kahneman（带着批判阅读）","en":"Thinking, Fast and Slow — Daniel Kahneman (read critically)"},{"zh":"The Man Who Mistook His Wife for a Hat — Oliver Sacks","en":"The Man Who Mistook His Wife for a Hat — Oliver Sacks"},{"zh":"The Seven Sins of Memory — Daniel Schacter","en":"The Seven Sins of Memory — Daniel Schacter"},{"zh":"Bad Science — Ben Goldacre","en":"Bad Science — Ben Goldacre"}],"summer":[{"name":"Cambridge Psychology Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"University-run psychology research or methods programmes","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"}],"ceiling":98,"portfolio":false},{"id":"media","math":10,"weights":{"fm":3,"physics":2,"chemistry":1,"economics":15,"biology":2,"psychology":18,"business":12},"essential":[],"recommended":["psychology","economics"],"synergies":[[["psychology","economics"],6],[["psychology","business"],5]],"note":{"zh":"传媒通常没有统一的必修A-Level，但需要持续阅读、论证、研究受众，并理解平台、商业模式和社会影响。","en":"Media courses rarely share one required A-level combination, but they demand sustained reading, argument, audience research and an understanding of platforms, business models and social impact."},"study":[{"zh":"训练文本和影像分析：谁在说、对谁说、通过什么平台、得到什么利益。","en":"Analyse texts and images by asking who speaks, to whom, through which platform and with what incentives."},{"zh":"学习基础统计和调查方法，避免只凭个人感受判断传播效果。","en":"Learn basic statistics and survey methods so communication claims are not based on intuition alone."},{"zh":"持续写短评、研究笔记或案例分析，形成清晰观点。","en":"Write short critiques, research notes or case analyses regularly to develop a clear voice."}],"epq":[{"zh":"算法推荐是否让校园信息传播更集中于少数账号？","en":"Do recommendation algorithms concentrate school information around a small number of accounts?"},{"zh":"品牌危机回应中的语言框架如何影响公众信任？","en":"How does linguistic framing in crisis responses affect public trust?"},{"zh":"推荐算法是在反映受众兴趣，还是在主动塑造公共议题？","en":"Do recommendation algorithms reflect audience interests, or actively shape the public agenda?"},{"zh":"短视频新闻能否在不牺牲准确性的前提下提高公共参与？","en":"Can short-form video news increase public engagement without sacrificing accuracy?"}],"courses":[{"name":"OpenLearn: Society, Politics & Law","url":"https://www.open.edu/openlearn/society/free-courses"},{"name":"Oxford Supercurricular Hub","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"},{"name":"MIT OpenCourseWare: Media Studies resources","url":"https://ocw.mit.edu/search/?q=media%20studies"},{"name":"OpenLearn: Creative Writing","url":"https://www.open.edu/openlearn/history-the-arts/creative-writing/content-section-overview"}],"books":[{"zh":"Amusing Ourselves to Death — Neil Postman","en":"Amusing Ourselves to Death — Neil Postman"},{"zh":"The Culture of Connectivity — José van Dijck","en":"The Culture of Connectivity — José van Dijck"},{"zh":"Convergence Culture — Henry Jenkins","en":"Convergence Culture — Henry Jenkins"},{"zh":"The Medium is the Massage — Marshall McLuhan & Quentin Fiore","en":"The Medium is the Massage — Marshall McLuhan & Quentin Fiore"}],"summer":[{"name":"Cambridge Subject Masterclasses in social sciences or languages","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"University-run journalism, film or digital media workshops","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"}],"ceiling":88,"portfolio":false},{"id":"acct","math":20,"weights":{"fm":11,"physics":4,"chemistry":2,"economics":19,"biology":1,"psychology":4,"business":18},"essential":[],"recommended":["economics"],"synergies":[[["economics","business"],4],[["fm","economics"],5]],"note":{"zh":"多数会计课程不要求Accounting A-Level，更看重数学能力、商业理解、写作，以及对规则和判断边界的认识。","en":"An Accounting A level is not usually required. Quantitative ability, business understanding, writing and awareness of where rules end and judgement begins matter more."},"study":[{"zh":"把比率、现金流和利润放回企业经营情境，不要只记公式。","en":"Put ratios, cash flow and profit back into business context rather than memorising formulas."},{"zh":"理解财务报表之间的勾稽关系，并练习解释异常变化。","en":"Understand how financial statements connect and practise explaining unusual movements."},{"zh":"关注审计、治理、税务和可持续披露中的职业判断。","en":"Explore professional judgement in audit, governance, tax and sustainability reporting."}],"epq":[{"zh":"收入确认规则如何改变不同商业模式下的利润表现？","en":"How do revenue-recognition rules change reported profit across business models?"},{"zh":"AI辅助审计能否降低舞弊风险，还是会带来新的盲点？","en":"Can AI-assisted audit reduce fraud risk, or does it introduce new blind spots?"},{"zh":"公允价值计量会提高报表透明度，还是放大短期波动？","en":"Does fair-value accounting improve transparency, or amplify short-term volatility?"},{"zh":"自动化审计工具能否可靠识别异常，而不增加新的盲点？","en":"Can automated audit tools identify anomalies reliably without creating new blind spots?"}],"courses":[{"name":"OpenLearn: Money & Business free courses","url":"https://www.open.edu/openlearn/money-business/free-courses"},{"name":"MIT OCW: Principles of Microeconomics","url":"https://ocw.mit.edu/courses/14-01sc-principles-of-microeconomics-fall-2011/"},{"name":"OpenLearn: Introduction to Bookkeeping and Accounting","url":"https://www.open.edu/openlearn/money-business/introduction-bookkeeping-and-accounting/content-section-overview"},{"name":"Coursera: Financial Accounting Fundamentals","url":"https://www.coursera.org/learn/uva-darden-financial-accounting"}],"books":[{"zh":"The End of Accounting — Baruch Lev & Feng Gu","en":"The End of Accounting — Baruch Lev & Feng Gu"},{"zh":"Financial Shenanigans — Howard Schilit","en":"Financial Shenanigans — Howard Schilit"},{"zh":"Financial Intelligence — Karen Berman & Joe Knight","en":"Financial Intelligence — Karen Berman & Joe Knight"},{"zh":"Accounting Made Simple — Mike Piper","en":"Accounting Made Simple — Mike Piper"}],"summer":[{"name":"University-run accounting, finance or business taster programmes","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"Cambridge Economics/Business-related Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"}],"ceiling":98,"portfolio":false},{"id":"finance","math":27,"weights":{"fm":27,"physics":8,"chemistry":4,"economics":23,"biology":1,"psychology":5,"business":11},"essential":[],"recommended":["fm","economics"],"synergies":[[["fm","economics"],10],[["fm","physics"],4]],"note":{"zh":"金融本科通常比学生想象中更数学化。Further Mathematics和Economics能分别支撑定量方法与市场理解，但并不能替代对数据、假设和风险的训练。","en":"Finance degrees are often more mathematical than students expect. Further Mathematics supports quantitative methods and Economics supports market reasoning, but neither replaces careful work with data, assumptions and risk."},"study":[{"zh":"巩固概率、统计、微积分和指数增长，理解公式背后的假设。","en":"Strengthen probability, statistics, calculus and exponential growth, and understand the assumptions behind formulas."},{"zh":"把Economics中的激励、信息和市场结构用于分析金融现象。","en":"Use incentives, information and market structure from Economics to analyse financial phenomena."},{"zh":"练习用数据检验自己的第一判断，也主动寻找反例。","en":"Use data to challenge your first judgement rather than searching only for confirmation."}],"epq":[{"zh":"动量策略在不同市场阶段是否仍然有效？","en":"Does a momentum strategy remain effective across different market regimes?"},{"zh":"利率变化如何影响成长型与价值型公司的估值？","en":"How do interest-rate changes affect the valuation of growth and value companies?"},{"zh":"被动投资规模扩大是否会削弱价格发现？","en":"Does the growth of passive investing weaken price discovery?"},{"zh":"先买后付服务如何改变年轻消费者的支出行为和信用风险？","en":"How do buy-now-pay-later services change young consumers’ spending behaviour and credit risk?"}],"courses":[{"name":"MIT OCW: Principles of Microeconomics","url":"https://ocw.mit.edu/courses/14-01sc-principles-of-microeconomics-fall-2011/"},{"name":"MIT OCW: Single Variable Calculus","url":"https://ocw.mit.edu/courses/18-01sc-single-variable-calculus-fall-2010/"},{"name":"Yale / Coursera: Financial Markets","url":"https://www.coursera.org/learn/financial-markets-global"},{"name":"MIT OCW: Finance Theory I","url":"https://ocw.mit.edu/courses/15-401-finance-theory-i-fall-2008/"}],"books":[{"zh":"The Intelligent Investor — Benjamin Graham（结合现代市场批判阅读）","en":"The Intelligent Investor — Benjamin Graham (read critically in a modern context)"},{"zh":"Against the Gods — Peter L. Bernstein","en":"Against the Gods — Peter L. Bernstein"},{"zh":"A Random Walk Down Wall Street — Burton G. Malkiel","en":"A Random Walk Down Wall Street — Burton G. Malkiel"},{"zh":"The Man Who Solved the Market — Gregory Zuckerman","en":"The Man Who Solved the Market — Gregory Zuckerman"}],"summer":[{"name":"Cambridge Economics Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"University-run finance/economics quantitative summer programmes","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"}],"ceiling":98,"portfolio":false},{"id":"civil","math":25,"weights":{"fm":19,"physics":29,"chemistry":6,"economics":4,"biology":3,"psychology":2,"business":4},"essential":["physics"],"recommended":["fm"],"synergies":[[["fm","physics"],9]],"note":{"zh":"数学和物理是土木工程最直接的基础。进一步数学会帮助结构分析和建模，但真实工程还需要材料、环境、施工和安全意识。","en":"Mathematics and Physics are the most direct foundations for Civil Engineering. Further Mathematics supports structural analysis and modelling, while real engineering also requires materials, environmental, construction and safety awareness."},"study":[{"zh":"把静力学、力矩、材料变形和流体问题放进真实结构情境。","en":"Apply statics, moments, material deformation and fluids to real structures."},{"zh":"训练数量级估算、单位检查和安全系数思维。","en":"Practise order-of-magnitude estimates, unit checking and safety-factor reasoning."},{"zh":"关注工程方案对成本、碳排放、维护和社区的影响。","en":"Consider cost, carbon, maintenance and community impact in engineering choices."}],"epq":[{"zh":"不同桥梁结构在相同材料用量下的承载效率如何比较？","en":"How do bridge forms compare in load efficiency for the same material quantity?"},{"zh":"城市雨洪设计中，透水铺装能减少多少峰值径流？","en":"How much can permeable paving reduce peak runoff in urban drainage?"},{"zh":"模块化建造是否一定比传统施工拥有更低的全生命周期碳排放？","en":"Does modular construction always have lower whole-life carbon emissions than conventional building?"},{"zh":"城市排水系统应如何应对更频繁的极端降雨？","en":"How should urban drainage systems respond to more frequent extreme rainfall?"}],"courses":[{"name":"MIT OCW: Classical Mechanics","url":"https://ocw.mit.edu/courses/8-01sc-classical-mechanics-fall-2016/"},{"name":"Isaac Physics","url":"https://isaacphysics.org/"},{"name":"MIT OCW: Solid Mechanics","url":"https://ocw.mit.edu/courses/1-050-solid-mechanics-fall-2004/"},{"name":"MIT OCW: Uncertainty in Engineering","url":"https://ocw.mit.edu/courses/1-010-uncertainty-in-engineering-fall-2008/"}],"books":[{"zh":"Structures: Or Why Things Don’t Fall Down — J. E. Gordon","en":"Structures: Or Why Things Don’t Fall Down — J. E. Gordon"},{"zh":"The Works: Anatomy of a City — Kate Ascher","en":"The Works: Anatomy of a City — Kate Ascher"},{"zh":"Why Buildings Fall Down — Matthys Levy & Mario Salvadori","en":"Why Buildings Fall Down — Matthys Levy & Mario Salvadori"},{"zh":"The Tower and the Bridge — David P. Billington","en":"The Tower and the Bridge — David P. Billington"}],"summer":[{"name":"Imperial Global Summer School","url":"https://www.imperial.ac.uk/be-inspired/global-summer-school/"},{"name":"Cambridge Engineering Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"}],"ceiling":98,"portfolio":false},{"id":"eee","math":29,"weights":{"fm":26,"physics":32,"chemistry":5,"economics":2,"biology":3,"psychology":2,"business":2},"essential":["physics"],"recommended":["fm"],"synergies":[[["fm","physics"],11]],"note":{"zh":"电子与电气工程高度依赖数学和物理，尤其是电学、波、微积分和复数。Further Mathematics会明显提升准备度。","en":"Electrical and Electronic Engineering relies heavily on Mathematics and Physics, especially electricity, waves, calculus and complex numbers. Further Mathematics is a strong advantage."},"study":[{"zh":"把电路题从代公式提升到建立等效模型、分析边界条件。","en":"Move from substituting formulas in circuits to building equivalent models and analysing boundary conditions."},{"zh":"补充复数、微分方程、矩阵和信号表示。","en":"Strengthen complex numbers, differential equations, matrices and signal representation."},{"zh":"做硬件项目时同时记录测量误差、噪声和安全。","en":"In hardware projects, document measurement error, noise and safety."}],"epq":[{"zh":"低成本传感器的噪声如何影响健康或环境监测？","en":"How does noise in low-cost sensors affect health or environmental monitoring?"},{"zh":"不同滤波方法对语音信号质量有何影响？","en":"How do different filtering methods affect speech-signal quality?"},{"zh":"边缘计算在什么情况下比云端计算更节能、更及时？","en":"When is edge computing more energy-efficient and responsive than cloud computing?"},{"zh":"电池管理系统能在多大程度上延长锂电池寿命？","en":"To what extent can a battery-management system extend lithium-ion battery life?"}],"courses":[{"name":"MIT OCW: Classical Mechanics / introductory physics","url":"https://ocw.mit.edu/courses/8-01sc-classical-mechanics-fall-2016/"},{"name":"Isaac Physics","url":"https://isaacphysics.org/"},{"name":"MIT OCW: Circuits and Electronics","url":"https://ocw.mit.edu/courses/6-002-circuits-and-electronics-spring-2007/"},{"name":"Khan Academy: Electrical Engineering","url":"https://www.khanacademy.org/science/electrical-engineering"}],"books":[{"zh":"The Information — James Gleick","en":"The Information — James Gleick"},{"zh":"The Art of Electronics — Paul Horowitz & Winfield Hill（选读）","en":"The Art of Electronics — Paul Horowitz & Winfield Hill (selected chapters)"},{"zh":"Make: Electronics — Charles Platt","en":"Make: Electronics — Charles Platt"},{"zh":"The Idea Factory — Jon Gertner","en":"The Idea Factory — Jon Gertner"}],"summer":[{"name":"Imperial Global Summer School","url":"https://www.imperial.ac.uk/be-inspired/global-summer-school/"},{"name":"Cambridge Engineering Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"}],"ceiling":98,"portfolio":false},{"id":"mgmt","math":13,"weights":{"fm":7,"physics":3,"chemistry":2,"economics":18,"biology":2,"psychology":15,"business":18},"essential":[],"recommended":["economics","psychology"],"synergies":[[["economics","psychology"],6],[["economics","business"],3]],"note":{"zh":"管理学没有统一必修科目。更好的准备是分析组织、市场、数据和人的行为，而非背诵商业案例。Economics、Psychology和数学各提供不同角度。","en":"Management has no universal required subject combination. Strong preparation is not memorising business cases but analysing organisations, markets, data and behaviour. Economics, Psychology and Mathematics each add a different lens."},"study":[{"zh":"案例分析必须区分事实、假设、利益相关者和评价标准。","en":"In case analysis, separate facts, assumptions, stakeholders and evaluation criteria."},{"zh":"用Economics看激励，用Psychology看行为，用数学看数据。","en":"Use Economics for incentives, Psychology for behaviour and Mathematics for evidence."},{"zh":"练习写出可执行方案，并说明风险和替代选项。","en":"Write actionable proposals and explain risks and alternatives."}],"epq":[{"zh":"绩效排名会提高效率，还是损害团队合作？","en":"Do performance rankings improve efficiency or damage teamwork?"},{"zh":"不同定价方式如何影响校园活动的参与和公平？","en":"How do different pricing models affect participation and fairness in school activities?"},{"zh":"混合办公对生产率的影响，为什么会因团队和任务不同而变化？","en":"Why does hybrid work affect productivity differently across teams and tasks?"},{"zh":"绩效指标在什么情况下会诱导员工追求数字而忽略真正目标？","en":"When do performance metrics encourage employees to chase numbers rather than real goals?"}],"courses":[{"name":"OpenLearn: Money & Business","url":"https://www.open.edu/openlearn/money-business/free-courses"},{"name":"MIT OCW: Principles of Microeconomics","url":"https://ocw.mit.edu/courses/14-01sc-principles-of-microeconomics-fall-2011/"},{"name":"OpenLearn: Leadership and Management","url":"https://www.open.edu/openlearn/money-business/leadership-management"},{"name":"Wharton / Coursera: Introduction to Marketing","url":"https://www.coursera.org/learn/wharton-marketing"}],"books":[{"zh":"The Goal — Eliyahu Goldratt","en":"The Goal — Eliyahu Goldratt"},{"zh":"Good Strategy/Bad Strategy — Richard Rumelt","en":"Good Strategy/Bad Strategy — Richard Rumelt"},{"zh":"High Output Management — Andrew Grove","en":"High Output Management — Andrew Grove"},{"zh":"The Innovator’s Dilemma — Clayton Christensen","en":"The Innovator’s Dilemma — Clayton Christensen"}],"summer":[{"name":"Cambridge Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"University-run business, entrepreneurship or organisation taster programmes","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"}],"ceiling":98,"portfolio":false},{"id":"phil","math":12,"weights":{"fm":9,"physics":6,"chemistry":2,"economics":10,"biology":3,"psychology":12,"business":3},"essential":[],"recommended":["psychology","economics"],"synergies":[[["fm","psychology"],4]],"note":{"zh":"哲学通常不要求特定A-Level。真正关键的是能读难文本、重建论证、发现隐含前提，并写出清楚而公平的反驳。","en":"Philosophy usually has no specific A-level requirement. The key is reading difficult texts, reconstructing arguments, finding hidden assumptions and writing clear, fair objections."},"study":[{"zh":"每读一篇文章，先画论证结构，再评价结论。","en":"For each text, map the argument before evaluating the conclusion."},{"zh":"区分“我不同意”和“这个论证不成立”。","en":"Distinguish “I disagree” from “the argument is invalid or unsound”."},{"zh":"数学和物理可以训练形式推理，Psychology能提供心灵哲学和认知问题。","en":"Mathematics and Physics train formal reasoning, while Psychology opens questions in philosophy of mind and cognition."}],"epq":[{"zh":"大型语言模型是否“理解”它生成的句子？","en":"Do large language models understand the sentences they generate?"},{"zh":"道德责任是否要求一个人本可以做出不同选择？","en":"Does moral responsibility require that a person could have acted otherwise?"},{"zh":"当AI给出建议时，人是否仍应对最终决定承担完整责任？","en":"When AI gives advice, should humans retain full responsibility for the final decision?"},{"zh":"如果一个人的记忆发生根本变化，他还是原来的那个人吗？","en":"If a person’s memories change fundamentally, are they still the same person?"}],"courses":[{"name":"Oxford Supercurricular Hub: Philosophy","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"},{"name":"Gresham College lectures","url":"https://www.gresham.ac.uk/watch-now"},{"name":"Yale Open Courses: Philosophy of Death","url":"https://oyc.yale.edu/philosophy/phil-176"},{"name":"MIT OCW: Problems of Philosophy","url":"https://ocw.mit.edu/courses/24-00-problems-of-philosophy-fall-2010/"}],"books":[{"zh":"What Does It All Mean? — Thomas Nagel","en":"What Does It All Mean? — Thomas Nagel"},{"zh":"The Problems of Philosophy — Bertrand Russell","en":"The Problems of Philosophy — Bertrand Russell"},{"zh":"Think — Simon Blackburn","en":"Think — Simon Blackburn"},{"zh":"Justice — Michael Sandel","en":"Justice — Michael Sandel"}],"summer":[{"name":"Cambridge Philosophy Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"University-run philosophy essay or discussion programmes","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"}],"ceiling":98,"portfolio":false},{"id":"swe","math":25,"weights":{"fm":24,"physics":12,"chemistry":3,"economics":4,"biology":2,"psychology":4,"business":4},"essential":[],"recommended":["fm"],"synergies":[[["fm","physics"],6]],"note":{"zh":"软件工程既需要计算基础，也需要把需求、团队协作、测试和长期维护做扎实。只会快速写出功能并不足够。","en":"Software Engineering needs computing foundations plus disciplined requirements, teamwork, testing and maintenance. Writing features quickly is not enough."},"study":[{"zh":"学习数据结构、算法和复杂度，避免只依赖框架。","en":"Learn data structures, algorithms and complexity rather than relying only on frameworks."},{"zh":"练习Git、测试、代码审查和清晰文档。","en":"Practise Git, testing, code review and clear documentation."},{"zh":"做项目时处理真实需求变化、错误恢复和安全问题。","en":"In projects, deal with changing requirements, failure recovery and security."}],"epq":[{"zh":"AI代码助手会提高软件质量，还是扩大隐藏缺陷？","en":"Do AI coding assistants improve software quality or amplify hidden defects?"},{"zh":"不同测试策略对持续迭代项目的缺陷发现率有何影响？","en":"How do testing strategies affect defect discovery in continuously evolving software?"},{"zh":"微服务架构在什么规模下会带来更多复杂度而不是收益？","en":"At what scale does a microservices architecture create more complexity than value?"},{"zh":"软件供应链中的开源依赖会带来哪些难以发现的安全风险？","en":"What hidden security risks arise from open-source dependencies in the software supply chain?"}],"courses":[{"name":"MIT OCW: Introduction to CS and Python","url":"https://ocw.mit.edu/courses/6-0001-introduction-to-computer-science-and-programming-in-python-fall-2016/"},{"name":"Isaac Computer Science","url":"https://isaaccomputerscience.org/"},{"name":"Harvard CS50 Web Programming","url":"https://cs50.harvard.edu/web/"},{"name":"University of Helsinki: Full Stack Open","url":"https://fullstackopen.com/en/"}],"books":[{"zh":"The Pragmatic Programmer — Andrew Hunt & David Thomas","en":"The Pragmatic Programmer — Andrew Hunt & David Thomas"},{"zh":"A Philosophy of Software Design — John Ousterhout","en":"A Philosophy of Software Design — John Ousterhout"},{"zh":"Clean Code — Robert C. Martin（批判性选读）","en":"Clean Code — Robert C. Martin (read critically and selectively)"},{"zh":"The Mythical Man-Month — Frederick Brooks","en":"The Mythical Man-Month — Frederick Brooks"}],"summer":[{"name":"Cambridge Computer Science Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"Imperial high-school computing programmes","url":"https://www.imperial.ac.uk/study/visit/summer-schools/high-school/"}],"ceiling":98,"portfolio":false},{"id":"bio","math":12,"weights":{"fm":5,"physics":5,"chemistry":24,"economics":2,"biology":32,"psychology":5,"business":1},"essential":["biology"],"recommended":["chemistry"],"synergies":[[["biology","chemistry"],11],[["biology","fm"],3]],"note":{"zh":"Biology通常是最直接的科目，Chemistry对分子、细胞和生物化学方向尤其重要。只记事实不够，要能解释机制和评价证据。","en":"Biology is the most direct subject, while Chemistry is especially important for molecular, cellular and biochemical routes. Memorising facts is not enough; you need to explain mechanisms and evaluate evidence."},"study":[{"zh":"把每个生物现象追问到机制、证据和例外。","en":"For each biological phenomenon, ask about mechanism, evidence and exceptions."},{"zh":"补充统计、实验设计和数据可视化。","en":"Strengthen statistics, experimental design and data visualisation."},{"zh":"阅读论文时关注对照组、重复、效应量和伦理。","en":"When reading papers, examine controls, replication, effect size and ethics."}],"epq":[{"zh":"温度或pH如何影响一种酶的活性与稳定性？","en":"How do temperature or pH affect the activity and stability of an enzyme?"},{"zh":"城市化是否改变校园周边的昆虫多样性？","en":"Does urbanisation change insect diversity around a school campus?"},{"zh":"肠道微生物与健康之间的关联，有多少能被现有研究解释为因果？","en":"How much of the association between the gut microbiome and health can current evidence treat as causal?"},{"zh":"遗传多样性在小型濒危种群保护中应占多大权重？","en":"How much weight should genetic diversity carry in conserving small endangered populations?"}],"courses":[{"name":"MIT OCW: Fundamentals of Biology","url":"https://ocw.mit.edu/courses/7-01sc-fundamentals-of-biology-fall-2011/"},{"name":"Our World in Data: Health and environment datasets","url":"https://ourworldindata.org/"},{"name":"MIT OCW: Introductory Biology","url":"https://ocw.mit.edu/courses/7-016-introductory-biology-fall-2018/"},{"name":"HHMI BioInteractive","url":"https://www.biointeractive.org/classroom-resources"}],"books":[{"zh":"The Selfish Gene — Richard Dawkins（比较不同层次的选择）","en":"The Selfish Gene — Richard Dawkins (compare levels of selection)"},{"zh":"The Gene: An Intimate History — Siddhartha Mukherjee","en":"The Gene: An Intimate History — Siddhartha Mukherjee"},{"zh":"The Gene — Siddhartha Mukherjee","en":"The Gene — Siddhartha Mukherjee"},{"zh":"The Vital Question — Nick Lane","en":"The Vital Question — Nick Lane"}],"summer":[{"name":"University-run biology or laboratory summer programmes","url":"https://www.imperial.ac.uk/study/visit/summer-schools/high-school/"},{"name":"Cambridge Natural Sciences Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"}],"ceiling":98,"portfolio":false},{"id":"ai","math":30,"weights":{"fm":29,"physics":13,"chemistry":3,"economics":6,"biology":4,"psychology":7,"business":2},"essential":[],"recommended":["fm"],"synergies":[[["fm","physics"],7],[["fm","psychology"],4]],"note":{"zh":"人工智能本科的核心仍是数学、算法和计算机系统。只会调用现成模型远远不够。Further Mathematics会明显增强准备度。","en":"The core of an AI degree is still mathematics, algorithms and computer systems, not simply calling ready-made models. Further Mathematics is a strong advantage."},"study":[{"zh":"重点补线性代数、概率、微积分和优化直觉。","en":"Focus on linear algebra, probability, calculus and optimisation intuition."},{"zh":"从零实现简单模型，再使用框架，比较两者理解差异。","en":"Implement simple models from scratch before using frameworks, then compare what each approach reveals."},{"zh":"评价模型时同时看准确率、偏差、鲁棒性和可解释性。","en":"Evaluate models for accuracy, bias, robustness and interpretability."}],"epq":[{"zh":"训练数据中的类别不平衡如何影响模型公平？","en":"How does class imbalance in training data affect model fairness?"},{"zh":"小模型在特定任务上能否比通用大模型更可靠？","en":"Can a small specialised model be more reliable than a general large model on a focused task?"},{"zh":"减少算法偏差时，公平、准确率和可解释性之间会出现哪些冲突？","en":"What conflicts arise among fairness, accuracy and explainability when reducing algorithmic bias?"},{"zh":"合成数据能否同时保护隐私并保留足够的分析价值？","en":"Can synthetic data protect privacy while retaining enough analytical value?"}],"courses":[{"name":"MIT OCW: Introduction to CS and Python","url":"https://ocw.mit.edu/courses/6-0001-introduction-to-computer-science-and-programming-in-python-fall-2016/"},{"name":"Coursera: Data Science and Machine Learning","url":"https://www.coursera.org/browse/data-science"},{"name":"Elements of AI","url":"https://www.elementsofai.com/"},{"name":"DeepLearning.AI: AI for Everyone","url":"https://www.coursera.org/learn/ai-for-everyone"}],"books":[{"zh":"The Alignment Problem — Brian Christian","en":"The Alignment Problem — Brian Christian"},{"zh":"Pattern Recognition and Machine Learning — Christopher Bishop（选读）","en":"Pattern Recognition and Machine Learning — Christopher Bishop (selected chapters)"},{"zh":"Human Compatible — Stuart Russell","en":"Human Compatible — Stuart Russell"},{"zh":"Deep Learning — Ian Goodfellow, Yoshua Bengio & Aaron Courville（选读）","en":"Deep Learning — Ian Goodfellow, Yoshua Bengio & Aaron Courville (selected chapters)"}],"summer":[{"name":"Imperial high-school computing/AI programmes","url":"https://www.imperial.ac.uk/study/visit/summer-schools/high-school/"},{"name":"Cambridge Computer Science Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"}],"ceiling":98,"portfolio":false},{"id":"trade","math":14,"weights":{"fm":6,"physics":2,"chemistry":2,"economics":25,"biology":1,"psychology":7,"business":20},"essential":[],"recommended":["economics"],"synergies":[[["economics","business"],5],[["economics","psychology"],3]],"note":{"zh":"国际贸易需要经济学框架，也需要理解企业、制度、政治风险和跨文化沟通。课程组合不能代替持续关注真实贸易数据和政策。","en":"International Trade needs economic frameworks plus an understanding of firms, institutions, political risk and cross-cultural communication. Subject choices cannot replace regular work with real trade data and policy."},"study":[{"zh":"掌握比较优势、汇率、贸易政策和全球价值链。","en":"Master comparative advantage, exchange rates, trade policy and global value chains."},{"zh":"用数据比较国家和产业，不把相关性写成因果。","en":"Use data to compare countries and industries without turning correlation into causation."},{"zh":"利用Chinese的双语优势阅读中英文政策与企业资料。","en":"Use Chinese bilingual ability to compare policy and company sources in two languages."}],"epq":[{"zh":"关税变化如何影响某一产业的价格、就业与供应链？","en":"How do tariff changes affect prices, employment and supply chains in one industry?"},{"zh":"跨境电商是否降低了中小企业进入国际市场的门槛？","en":"Has cross-border e-commerce lowered barriers for small firms entering international markets?"},{"zh":"供应链回流能提高韧性，但企业愿意承担多大的成本？","en":"How much cost are firms willing to bear for the resilience gained from reshoring supply chains?"},{"zh":"碳边境调节机制会推动绿色转型，还是形成新的贸易壁垒？","en":"Will carbon border adjustments accelerate green transition, or create new trade barriers?"}],"courses":[{"name":"MIT OCW: Principles of Microeconomics","url":"https://ocw.mit.edu/courses/14-01sc-principles-of-microeconomics-fall-2011/"},{"name":"Our World in Data","url":"https://ourworldindata.org/"},{"name":"WTO E-Learning","url":"https://www.wto.org/english/res_e/d_learn_e/d_learn_e.htm"},{"name":"World Bank Open Learning Campus","url":"https://www.worldbank.org/en/olc"}],"books":[{"zh":"The Box — Marc Levinson","en":"The Box — Marc Levinson"},{"zh":"The Travels of a T-Shirt in the Global Economy — Pietra Rivoli","en":"The Travels of a T-Shirt in the Global Economy — Pietra Rivoli"},{"zh":"Globalization and Its Discontents — Joseph E. Stiglitz","en":"Globalization and Its Discontents — Joseph E. Stiglitz"},{"zh":"The World for Sale — Javier Blas & Jack Farchy","en":"The World for Sale — Javier Blas & Jack Farchy"}],"summer":[{"name":"Cambridge Economics Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"University-run international economics or global affairs programmes","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"}],"ceiling":98,"portfolio":false},{"id":"physics","math":29,"weights":{"fm":31,"physics":35,"chemistry":7,"economics":2,"biology":3,"psychology":2,"business":0},"essential":["physics"],"recommended":["fm"],"synergies":[[["fm","physics"],13]],"note":{"zh":"Physics和Mathematics是核心，Further Mathematics对顶尖课程和理论方向尤其重要。物理准备度还体现在建模、估算和实验判断上。","en":"Physics and Mathematics are core, and Further Mathematics is especially valuable for selective or theoretical routes. Preparation is not only speed in solving problems, but modelling, estimation and experimental judgement."},"study":[{"zh":"练习从基本原理推导，不依赖记忆公式。","en":"Practise deriving results from first principles rather than relying on memorised formulas."},{"zh":"补微积分、向量、微分方程和复数。","en":"Strengthen calculus, vectors, differential equations and complex numbers."},{"zh":"做实验时主动分析系统误差、随机误差和模型限制。","en":"In experiments, distinguish systematic and random error and discuss model limits."}],"epq":[{"zh":"空气阻力模型在什么速度范围内最能解释真实下落？","en":"Over what speed range does a drag model best explain real falling motion?"},{"zh":"太阳能电池的温度系数如何影响实际发电量？","en":"How does the temperature coefficient of a solar cell affect real power output?"},{"zh":"量子密码在真实设备中能否实现理论上的无条件安全？","en":"Can quantum cryptography deliver theoretical unconditional security in real devices?"},{"zh":"一个简化模型能在多大程度上预测双摆的混沌运动？","en":"How far can a simplified model predict the chaotic motion of a double pendulum?"}],"courses":[{"name":"MIT OCW: Classical Mechanics","url":"https://ocw.mit.edu/courses/8-01sc-classical-mechanics-fall-2016/"},{"name":"Isaac Physics","url":"https://isaacphysics.org/"},{"name":"MIT OCW: Electricity and Magnetism","url":"https://ocw.mit.edu/courses/8-02sc-physics-ii-electricity-and-magnetism-fall-2010/"},{"name":"Perimeter Institute Educational Outreach","url":"https://www.perimeterinstitute.ca/training/educational-outreach"}],"books":[{"zh":"Six Easy Pieces — Richard Feynman","en":"Six Easy Pieces — Richard Feynman"},{"zh":"The Character of Physical Law — Richard Feynman","en":"The Character of Physical Law — Richard Feynman"},{"zh":"The Theoretical Minimum — Leonard Susskind & George Hrabovsky","en":"The Theoretical Minimum — Leonard Susskind & George Hrabovsky"},{"zh":"QED: The Strange Theory of Light and Matter — Richard Feynman","en":"QED: The Strange Theory of Light and Matter — Richard Feynman"}],"summer":[{"name":"Imperial Global Summer School","url":"https://www.imperial.ac.uk/be-inspired/global-summer-school/"},{"name":"Cambridge Physics Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"}],"ceiling":98,"portfolio":false},{"id":"pharm","math":13,"weights":{"fm":4,"physics":5,"chemistry":35,"economics":1,"biology":27,"psychology":6,"business":1},"essential":["chemistry"],"recommended":["biology"],"synergies":[[["chemistry","biology"],13]],"note":{"zh":"Chemistry通常是药学最关键的科目，Biology能补充生理、药理和疾病机制。还要注意药学是受监管职业，不同国家的注册路径不同。","en":"Chemistry is usually the key subject for Pharmacy, while Biology supports physiology, pharmacology and disease mechanisms. Pharmacy is regulated, and registration routes differ by country."},"study":[{"zh":"把有机化学中的结构、官能团和反应与药物性质联系起来。","en":"Link organic structure, functional groups and reactions to drug properties."},{"zh":"理解剂量—反应、代谢、相互作用和风险收益。","en":"Understand dose–response, metabolism, interactions and risk–benefit."},{"zh":"练习准确记录实验和判断证据质量。","en":"Practise precise experimental records and judging evidence quality."}],"epq":[{"zh":"药物溶解度与pH之间的关系如何影响制剂设计？","en":"How does the relationship between drug solubility and pH affect formulation design?"},{"zh":"抗菌药使用行为如何推动耐药性？","en":"How do patterns of antimicrobial use drive resistance?"},{"zh":"抗生素管理政策怎样在个体治疗与群体耐药风险之间取舍？","en":"How should antibiotic-stewardship policy balance individual treatment and population-level resistance?"},{"zh":"药物基因组学在多大程度上能改善用药剂量和不良反应预测？","en":"To what extent can pharmacogenomics improve dosing and prediction of adverse drug reactions?"}],"courses":[{"name":"MIT OCW: Principles of Chemical Science","url":"https://ocw.mit.edu/courses/5-111sc-principles-of-chemical-science-fall-2014/"},{"name":"MIT OCW: Fundamentals of Biology","url":"https://ocw.mit.edu/courses/7-01sc-fundamentals-of-biology-fall-2011/"},{"name":"Coursera: Drug Development","url":"https://www.coursera.org/learn/drug-development"},{"name":"OpenLearn: Health Sciences","url":"https://www.open.edu/openlearn/science-maths-technology/health-sciences"}],"books":[{"zh":"Bad Pharma — Ben Goldacre","en":"Bad Pharma — Ben Goldacre"},{"zh":"The Drug Book — Michael C. Gerald（选读）","en":"The Drug Book — Michael C. Gerald (selected entries)"},{"zh":"The Billion-Dollar Molecule — Barry Werth","en":"The Billion-Dollar Molecule — Barry Werth"},{"zh":"Drug Discovery: A History — Walter Sneader","en":"Drug Discovery: A History — Walter Sneader"}],"summer":[{"name":"University-run pharmacy, chemistry or biomedical summer programmes","url":"https://www.imperial.ac.uk/study/visit/summer-schools/high-school/"},{"name":"Cambridge Natural Sciences Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"}],"ceiling":98,"portfolio":false},{"id":"math","math":35,"weights":{"fm":38,"physics":12,"chemistry":5,"economics":8,"biology":2,"psychology":2,"business":1},"essential":["fm"],"recommended":["physics"],"synergies":[[["fm","physics"],6]],"note":{"zh":"如果学校提供 Further Mathematics，申请数学尤其是顶尖数学课程时通常应选择。数学专业看重证明、抽象和解决陌生问题，计算速度只是其中一小部分。","en":"If Further Mathematics is offered, it is normally the direct choice for Mathematics, especially for selective courses. Mathematics degrees value proof, abstraction and unfamiliar problem solving rather than calculation speed alone."},"study":[{"zh":"练习证明：清楚写出定义、关键步骤和为何成立。","en":"Practise proof by stating definitions, key steps and why each step follows."},{"zh":"做陌生题时保留尝试、反例和失败路径。","en":"Keep attempts, counterexamples and failed routes when solving unfamiliar problems."},{"zh":"补组合、数论、图论、概率或线性代数中的一个方向。","en":"Explore one area beyond the syllabus, such as combinatorics, number theory, graph theory, probability or linear algebra."}],"epq":[{"zh":"不同投票制度满足哪些公平性条件，又必须牺牲什么？","en":"Which fairness conditions do voting systems satisfy, and what must they sacrifice?"},{"zh":"素数分布中的简单猜想能否通过计算实验得到支持？","en":"Can computational experiments support simple conjectures about prime distribution?"},{"zh":"不同投票制度能否同时满足公平性的多个条件？","en":"Can a voting system satisfy several reasonable conditions of fairness at the same time?"},{"zh":"传染病模型的结论对初始假设和参数误差有多敏感？","en":"How sensitive are epidemic-model conclusions to initial assumptions and parameter error?"}],"courses":[{"name":"MIT OCW: Single Variable Calculus","url":"https://ocw.mit.edu/courses/18-01sc-single-variable-calculus-fall-2010/"},{"name":"NRICH / Project Euler","url":"https://nrich.maths.org/"},{"name":"MIT OCW: Single Variable Calculus","url":"https://ocw.mit.edu/courses/18-01sc-single-variable-calculus-fall-2010/"},{"name":"OpenLearn: Mathematics and Statistics","url":"https://www.open.edu/openlearn/science-maths-technology/mathematics-statistics"}],"books":[{"zh":"How to Prove It — Daniel Velleman","en":"How to Prove It — Daniel Velleman"},{"zh":"The Art and Craft of Problem Solving — Paul Zeitz","en":"The Art and Craft of Problem Solving — Paul Zeitz"},{"zh":"How Not to Be Wrong — Jordan Ellenberg","en":"How Not to Be Wrong — Jordan Ellenberg"},{"zh":"Infinite Powers — Steven Strogatz","en":"Infinite Powers — Steven Strogatz"}],"summer":[{"name":"Cambridge Mathematics Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"University-run proof/problem-solving programmes","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"}],"ceiling":98,"portfolio":false},{"id":"chem","math":15,"weights":{"fm":8,"physics":14,"chemistry":35,"economics":1,"biology":15,"psychology":2,"business":0},"essential":["chemistry"],"recommended":["physics","biology"],"synergies":[[["chemistry","physics"],6],[["chemistry","biology"],7]],"note":{"zh":"Chemistry是核心；Physics适合物理化学和材料方向，Biology适合生化和药物方向。数学会越来越重要。","en":"Chemistry is core. Physics supports physical chemistry and materials, while Biology supports biochemical and pharmaceutical directions. Mathematics becomes increasingly important."},"study":[{"zh":"不要只记反应；追问结构、能量、动力学和平衡。","en":"Do not only memorise reactions; ask about structure, energy, kinetics and equilibrium."},{"zh":"练习处理实验数据、不确定度和异常值。","en":"Practise handling experimental data, uncertainty and anomalies."},{"zh":"把微观模型与宏观性质联系起来。","en":"Connect microscopic models to macroscopic properties."}],"epq":[{"zh":"催化剂如何改变反应速率而不改变平衡位置？","en":"How does a catalyst change reaction rate without shifting equilibrium?"},{"zh":"不同聚合物结构如何影响热稳定性和回收难度？","en":"How do polymer structures affect thermal stability and recyclability?"},{"zh":"绿色溶剂是否总能在环境影响和反应性能之间取得更好平衡？","en":"Do green solvents always offer a better balance between environmental impact and reaction performance?"},{"zh":"催化剂降低活化能，却不改变平衡位置：这对工业反应设计意味着什么？","en":"Catalysts lower activation energy without changing equilibrium: what does this mean for industrial reaction design?"}],"courses":[{"name":"MIT OCW: Principles of Chemical Science","url":"https://ocw.mit.edu/courses/5-111sc-principles-of-chemical-science-fall-2014/"},{"name":"Coursera: Chemistry and physical science courses","url":"https://www.coursera.org/browse/physical-science-and-engineering"},{"name":"MIT OCW: Principles of Chemical Science","url":"https://ocw.mit.edu/courses/5-111sc-principles-of-chemical-science-fall-2014/"},{"name":"RSC Education Resources","url":"https://edu.rsc.org/resources"}],"books":[{"zh":"The Disappearing Spoon — Sam Kean","en":"The Disappearing Spoon — Sam Kean"},{"zh":"Stuff Matters — Mark Miodownik","en":"Stuff Matters — Mark Miodownik"},{"zh":"Molecules — Theodore Gray","en":"Molecules — Theodore Gray"},{"zh":"Why Chemical Reactions Happen — James Keeler & Peter Wothers（选读）","en":"Why Chemical Reactions Happen — James Keeler & Peter Wothers (selected chapters)"}],"summer":[{"name":"Imperial Global Summer School","url":"https://www.imperial.ac.uk/be-inspired/global-summer-school/"},{"name":"Cambridge Chemistry Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"}],"ceiling":98,"portfolio":false},{"id":"econ","math":29,"weights":{"fm":27,"physics":7,"chemistry":4,"economics":24,"biology":2,"psychology":8,"business":7},"essential":[],"recommended":["fm","economics"],"synergies":[[["fm","economics"],11],[["economics","psychology"],4]],"note":{"zh":"顶尖经济学课程往往非常数学化，Mathematics是关键，Further Mathematics通常很有帮助。Economics A-Level通常不是硬性要求，但能帮助学生建立学科语言和分析框架。","en":"Selective Economics courses are often highly mathematical. Mathematics is key and Further Mathematics is frequently valuable. Economics A level is not universally required, but it provides useful language and frameworks."},"study":[{"zh":"重点掌握微积分、概率、函数和数据解释。","en":"Prioritise calculus, probability, functions and data interpretation."},{"zh":"每个经济结论都追问识别策略：证据来自相关还是因果？","en":"For every economic claim, ask about identification: is the evidence correlational or causal?"},{"zh":"把理论用于真实政策，但明确模型假设和受影响群体。","en":"Apply theory to real policy while stating model assumptions and affected groups."}],"epq":[{"zh":"最低工资变化对青年就业的影响如何识别？","en":"How can the effect of minimum-wage changes on youth employment be identified?"},{"zh":"演唱会动态定价提高效率还是加剧不公平？","en":"Does dynamic concert pricing improve efficiency or worsen inequality?"},{"zh":"最低工资对就业的影响为什么会因地区和劳动力市场结构而不同？","en":"Why does the employment effect of a minimum wage differ across regions and labour-market structures?"},{"zh":"拥堵收费怎样在效率、环保和分配公平之间取得平衡？","en":"How can congestion pricing balance efficiency, environmental goals and distributional fairness?"}],"courses":[{"name":"MIT OCW: Principles of Microeconomics","url":"https://ocw.mit.edu/courses/14-01sc-principles-of-microeconomics-fall-2011/"},{"name":"Our World in Data","url":"https://ourworldindata.org/"},{"name":"MIT OCW: Principles of Microeconomics","url":"https://ocw.mit.edu/courses/14-01-principles-of-microeconomics-fall-2018/"},{"name":"CORE Econ","url":"https://www.core-econ.org/"}],"books":[{"zh":"The Undercover Economist — Tim Harford","en":"The Undercover Economist — Tim Harford"},{"zh":"Poor Economics — Abhijit Banerjee & Esther Duflo","en":"Poor Economics — Abhijit Banerjee & Esther Duflo"},{"zh":"The Armchair Economist — Steven E. Landsburg","en":"The Armchair Economist — Steven E. Landsburg"},{"zh":"Why Nations Fail — Daron Acemoglu & James A. Robinson","en":"Why Nations Fail — Daron Acemoglu & James A. Robinson"}],"summer":[{"name":"Cambridge Economics Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"University-run economics, data or public-policy programmes","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"}],"ceiling":98,"portfolio":false},{"id":"mse","math":23,"weights":{"fm":15,"physics":27,"chemistry":27,"economics":2,"biology":7,"psychology":1,"business":2},"essential":[],"recommended":["physics","chemistry"],"synergies":[[["physics","chemistry"],11],[["fm","physics"],4]],"note":{"zh":"材料科学横跨物理和化学。至少一门Physics或Chemistry通常很重要，两门同时选择会让结构—性质—加工的理解更完整。","en":"Materials Science bridges Physics and Chemistry. At least one is usually important, and taking both gives a fuller view of structure, properties and processing."},"study":[{"zh":"把键合、晶体结构、缺陷和相变与宏观性能联系起来。","en":"Connect bonding, crystal structure, defects and phase changes to macroscopic performance."},{"zh":"练习从应用需求反推材料选择与失效风险。","en":"Work backwards from application requirements to material choice and failure risk."},{"zh":"补充基础热力学、力学和实验表征。","en":"Strengthen basic thermodynamics, mechanics and characterisation."}],"epq":[{"zh":"不粘涂层的失效主要来自磨损、热降解还是界面结合？","en":"Is failure in non-stick coatings driven mainly by wear, thermal degradation or interfacial adhesion?"},{"zh":"不同可降解塑料在真实环境中的性能与降解如何权衡？","en":"How should performance and degradation be balanced in biodegradable plastics under real conditions?"},{"zh":"可降解聚合物能否在使用性能、成本和真实降解条件之间取得平衡？","en":"Can biodegradable polymers balance performance, cost and realistic degradation conditions?"},{"zh":"不同锂电池正极材料在能量密度、安全性和资源供应之间如何取舍？","en":"How do lithium-ion cathode materials trade off energy density, safety and resource supply?"}],"courses":[{"name":"MIT OCW: Principles of Chemical Science","url":"https://ocw.mit.edu/courses/5-111sc-principles-of-chemical-science-fall-2014/"},{"name":"Coursera: Physical Science and Engineering","url":"https://www.coursera.org/browse/physical-science-and-engineering"},{"name":"MIT OCW: Introduction to Solid-State Chemistry","url":"https://ocw.mit.edu/courses/3-091sc-introduction-to-solid-state-chemistry-fall-2010/"},{"name":"University of Cambridge DoITPoMS","url":"https://www.doitpoms.ac.uk/"}],"books":[{"zh":"Stuff Matters — Mark Miodownik","en":"Stuff Matters — Mark Miodownik"},{"zh":"The New Science of Strong Materials — J. E. Gordon","en":"The New Science of Strong Materials — J. E. Gordon"},{"zh":"Liquid Rules — Mark Miodownik","en":"Liquid Rules — Mark Miodownik"},{"zh":"The Alchemy of Us — Ainissa Ramirez","en":"The Alchemy of Us — Ainissa Ramirez"}],"summer":[{"name":"Imperial Global Summer School","url":"https://www.imperial.ac.uk/be-inspired/global-summer-school/"},{"name":"Cambridge Engineering/Natural Sciences Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"}],"ceiling":98,"portfolio":false},{"id":"ds","math":30,"weights":{"fm":29,"physics":9,"chemistry":4,"economics":13,"biology":5,"psychology":8,"business":5},"essential":[],"recommended":["fm"],"synergies":[[["fm","economics"],6],[["fm","psychology"],4]],"note":{"zh":"数据科学需要数学、统计、编程，也要能判断数据来源是否可靠。Further Mathematics通常会显著增强准备度。","en":"Data Science is not mainly about software tools; it is built on mathematics, statistics, programming and judgement about data provenance. Further Mathematics is a strong advantage."},"study":[{"zh":"补概率、统计、线性代数和微积分。","en":"Strengthen probability, statistics, linear algebra and calculus."},{"zh":"每次分析都先检查数据如何产生、缺失和偏差。","en":"Before every analysis, examine how the data was generated, what is missing and where bias may enter."},{"zh":"训练可复现分析：清理、代码、图表和解释要连成一条线。","en":"Build reproducible analyses linking cleaning, code, visualisation and interpretation."}],"epq":[{"zh":"缺失数据处理方法会如何改变结论？","en":"How do methods for handling missing data change conclusions?"},{"zh":"预测准确率提高时，模型公平性是否一定改善？","en":"Does higher predictive accuracy necessarily improve model fairness?"},{"zh":"缺失数据的处理方式会怎样改变对教育或健康差异的结论？","en":"How can the treatment of missing data change conclusions about educational or health inequality?"},{"zh":"预测模型的准确率提高时，公平性一定会随之改善吗？","en":"When predictive accuracy improves, does fairness necessarily improve as well?"}],"courses":[{"name":"Coursera: Data Science","url":"https://www.coursera.org/browse/data-science"},{"name":"MIT OCW: Single Variable Calculus","url":"https://ocw.mit.edu/courses/18-01sc-single-variable-calculus-fall-2010/"},{"name":"HarvardX Data Science Professional Certificate","url":"https://pll.harvard.edu/series/professional-certificate-data-science"},{"name":"Kaggle Learn","url":"https://www.kaggle.com/learn"}],"books":[{"zh":"Naked Statistics — Charles Wheelan","en":"Naked Statistics — Charles Wheelan"},{"zh":"The Signal and the Noise — Nate Silver","en":"The Signal and the Noise — Nate Silver"},{"zh":"Everybody Lies — Seth Stephens-Davidowitz","en":"Everybody Lies — Seth Stephens-Davidowitz"},{"zh":"The Book of Why — Judea Pearl & Dana Mackenzie","en":"The Book of Why — Judea Pearl & Dana Mackenzie"}],"summer":[{"name":"Cambridge Mathematics/Computer Science Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"University-run data science or quantitative research programmes","url":"https://www.imperial.ac.uk/study/visit/summer-schools/high-school/"}],"ceiling":98,"portfolio":false},{"id":"de","math":22,"weights":{"fm":15,"physics":24,"chemistry":6,"economics":7,"biology":5,"psychology":12,"business":10},"essential":[],"recommended":["physics","psychology"],"synergies":[[["physics","psychology"],7],[["physics","business"],5]],"note":{"zh":"设计工程需要数学和物理支撑技术可行性，也需要Psychology或Business帮助理解用户与落地。最终仍要靠项目和作品集证明综合能力。","en":"Design Engineering needs Mathematics and Physics for technical feasibility, plus Psychology or Business for users and implementation. Projects and a portfolio remain decisive."},"study":[{"zh":"同时训练工程分析、原型制作和用户研究。","en":"Develop engineering analysis, prototyping and user research together."},{"zh":"每个设计明确约束：成本、安全、环境、制造和使用情境。","en":"Define constraints for every design: cost, safety, environment, manufacture and context of use."},{"zh":"不要把“创新”写成外观变化，要证明问题和效果。","en":"Do not equate innovation with a new appearance; demonstrate the problem and impact."}],"epq":[{"zh":"如何设计更容易被老年人正确使用的药盒或设备？","en":"How can a medicine container or device be designed for safer use by older adults?"},{"zh":"低成本传感器能否改善校园能源管理？","en":"Can low-cost sensors improve school energy management?"},{"zh":"提高产品可维修性会在多大程度上牺牲轻薄、成本或防水性能？","en":"To what extent does repairability trade off against thinness, cost or water resistance?"},{"zh":"包容性设计怎样从少数用户的需求中产生更普遍的改进？","en":"How can inclusive design turn the needs of a minority of users into wider improvements?"}],"courses":[{"name":"Coursera: Physical Science and Engineering","url":"https://www.coursera.org/browse/physical-science-and-engineering"},{"name":"OpenLearn: Understanding customers","url":"https://www.open.edu/openlearn/money-business/understanding-your-customers/content-section-0?intro=1"},{"name":"MIT OCW: Product Engineering Processes","url":"https://ocw.mit.edu/courses/2-009-product-engineering-process-fall-2021/"},{"name":"OpenLearn: Design and Innovation","url":"https://www.open.edu/openlearn/science-maths-technology/design-innovation"}],"books":[{"zh":"The Design of Everyday Things — Don Norman","en":"The Design of Everyday Things — Don Norman"},{"zh":"Creative Confidence — Tom Kelley & David Kelley","en":"Creative Confidence — Tom Kelley & David Kelley"},{"zh":"Change by Design — Tim Brown","en":"Change by Design — Tim Brown"},{"zh":"The Innovator’s Dilemma — Clayton Christensen","en":"The Innovator’s Dilemma — Clayton Christensen"}],"summer":[{"name":"Imperial Global Summer School","url":"https://www.imperial.ac.uk/be-inspired/global-summer-school/"},{"name":"University-run design/engineering portfolio programmes","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"}],"ceiling":92,"portfolio":true},{"id":"cheme","math":27,"weights":{"fm":18,"physics":19,"chemistry":32,"economics":3,"biology":5,"psychology":1,"business":2},"essential":["chemistry"],"recommended":["physics","fm"],"synergies":[[["chemistry","physics"],8],[["chemistry","fm"],7]],"note":{"zh":"Chemical Engineering通常要求数学和化学，Physics与Further Mathematics会帮助流体、热力学和过程建模。化学工程关注的是系统设计、过程控制和规模化生产。","en":"Chemical Engineering usually requires Mathematics and Chemistry. Physics and Further Mathematics support fluids, thermodynamics and process modelling. It is not simply chemistry at a larger scale, but system design and control."},"study":[{"zh":"把化学平衡和动力学放进物料衡算、能量衡算和反应器情境。","en":"Place equilibrium and kinetics within material balances, energy balances and reactor contexts."},{"zh":"补微积分、微分方程、流体和热力学。","en":"Strengthen calculus, differential equations, fluids and thermodynamics."},{"zh":"所有方案都考虑安全、放大和环境后果。","en":"Consider safety, scale-up and environmental consequences in every proposal."}],"epq":[{"zh":"反应器温度控制如何影响产率与失控风险？","en":"How does reactor temperature control affect yield and runaway risk?"},{"zh":"碳捕集过程中的能耗与去除效率如何权衡？","en":"How should energy use and removal efficiency be balanced in carbon capture?"},{"zh":"绿色氢能从制取到运输的整体效率能否支持大规模应用？","en":"Can the end-to-end efficiency of green hydrogen support large-scale use?"},{"zh":"过程强化在缩小设备体积时会带来哪些安全和控制难题？","en":"What safety and control challenges arise when process intensification reduces equipment size?"}],"courses":[{"name":"MIT OCW: Principles of Chemical Science","url":"https://ocw.mit.edu/courses/5-111sc-principles-of-chemical-science-fall-2014/"},{"name":"MIT OCW: Single Variable Calculus","url":"https://ocw.mit.edu/courses/18-01sc-single-variable-calculus-fall-2010/"},{"name":"MIT OCW: Chemical Engineering Thermodynamics","url":"https://ocw.mit.edu/courses/10-213-chemical-and-biological-engineering-thermodynamics-spring-2002/"},{"name":"LearnChemE","url":"https://learncheme.com/"}],"books":[{"zh":"The Alchemy of Air — Thomas Hager","en":"The Alchemy of Air — Thomas Hager"},{"zh":"Chemical Process Safety: Learning from Case Histories — Roy Sanders（选读案例）","en":"Chemical Process Safety: Learning from Case Histories — Roy Sanders (selected cases)"},{"zh":"Energy and Civilization: A History — Vaclav Smil","en":"Energy and Civilization: A History — Vaclav Smil"},{"zh":"Sustainable Energy — Without the Hot Air — David MacKay","en":"Sustainable Energy — Without the Hot Air — David MacKay"}],"summer":[{"name":"Imperial Global Summer School","url":"https://www.imperial.ac.uk/be-inspired/global-summer-school/"},{"name":"Cambridge Chemical Engineering-related Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"}],"ceiling":98,"portfolio":false},{"id":"bme","math":24,"weights":{"fm":13,"physics":24,"chemistry":15,"economics":2,"biology":23,"psychology":4,"business":2},"essential":[],"recommended":["physics","biology"],"synergies":[[["physics","biology"],10],[["chemistry","biology"],7],[["fm","physics"],4]],"note":{"zh":"生物医学工程的课程要求差异较大：有的偏工程，重Physics；有的偏生物材料或分子方向，重Chemistry/Biology。应按目标课程模块核对。","en":"Biomedical Engineering requirements vary: engineering-heavy courses emphasise Physics, while biomaterials or molecular routes may emphasise Chemistry and Biology. Check the modules of each target course."},"study":[{"zh":"在数学和物理基础上学习生理系统，不把人体当成简单机器。","en":"Build on Mathematics and Physics while learning physiology without treating the body as a simple machine."},{"zh":"理解测量信号、噪声、安全和临床使用情境。","en":"Understand measurement signals, noise, safety and clinical context."},{"zh":"项目中同时说明技术指标与患者/医护需求。","en":"In projects, explain both technical specifications and patient or clinician needs."}],"epq":[{"zh":"可穿戴传感器的运动伪影会如何影响心率判断？","en":"How do motion artefacts in wearable sensors affect heart-rate interpretation?"},{"zh":"不同支架材料如何影响力学性能和细胞相容性？","en":"How do scaffold materials affect mechanical performance and cell compatibility?"},{"zh":"消费级可穿戴设备的健康数据在什么情况下足以支持医学判断？","en":"When is health data from consumer wearables reliable enough to support medical judgement?"},{"zh":"3D打印植入物的个性化优势如何与验证、监管和成本相平衡？","en":"How should the personalisation benefits of 3D-printed implants be balanced against validation, regulation and cost?"}],"courses":[{"name":"MIT OCW: Fundamentals of Biology","url":"https://ocw.mit.edu/courses/7-01sc-fundamentals-of-biology-fall-2011/"},{"name":"Coursera: Biomedical and engineering courses","url":"https://www.coursera.org/browse/physical-science-and-engineering"},{"name":"MIT OCW: Introduction to Bioengineering","url":"https://ocw.mit.edu/courses/20-010j-introduction-to-bioengineering-be-010j-spring-2006/"},{"name":"Coursera: Biomedical Sciences","url":"https://www.coursera.org/browse/health/biomedical-sciences"}],"books":[{"zh":"The Body: A Guide for Occupants — Bill Bryson","en":"The Body: A Guide for Occupants — Bill Bryson"},{"zh":"Biomedical Engineering: Bridging Medicine and Technology — W. Mark Saltzman（选读）","en":"Biomedical Engineering: Bridging Medicine and Technology — W. Mark Saltzman (selected chapters)"},{"zh":"The Gene: An Intimate History — Siddhartha Mukherjee","en":"The Gene: An Intimate History — Siddhartha Mukherjee"},{"zh":"The Emperor of All Maladies — Siddhartha Mukherjee","en":"The Emperor of All Maladies — Siddhartha Mukherjee"}],"summer":[{"name":"Imperial Global Summer School","url":"https://www.imperial.ac.uk/be-inspired/global-summer-school/"},{"name":"University-run biomedical or engineering research programmes","url":"https://www.imperial.ac.uk/study/visit/summer-schools/high-school/"}],"ceiling":98,"portfolio":false},{"id":"soc","math":11,"weights":{"fm":5,"physics":2,"chemistry":2,"economics":17,"biology":5,"psychology":18,"business":6},"essential":[],"recommended":["economics","psychology"],"synergies":[[["economics","psychology"],8]],"note":{"zh":"社会科学通常不要求特定科目，但需要阅读、写作、方法意识和对现实社会的持续观察。Psychology和Economics能提供不同分析尺度。","en":"Social Sciences often have no fixed subject requirement, but demand reading, writing, methodological awareness and sustained observation of society. Psychology and Economics provide different analytical scales."},"study":[{"zh":"区分规范性问题与经验性问题：我们希望怎样，和现实怎样。","en":"Separate normative from empirical questions: what should happen and what does happen."},{"zh":"同时接触定量与定性方法。","en":"Engage with both quantitative and qualitative methods."},{"zh":"比较不同理论对同一现象的解释，并判断各自证据。","en":"Compare how different theories explain the same phenomenon rather than seeking one answer."}],"epq":[{"zh":"社交媒体使用与青少年孤独感之间是什么关系？","en":"What is the relationship between social-media use and adolescent loneliness?"},{"zh":"城市公共空间的设计如何影响不同群体的使用？","en":"How does the design of urban public space affect use by different groups?"},{"zh":"社会流动应通过收入、教育、职业还是代际变化来衡量？","en":"Should social mobility be measured through income, education, occupation or intergenerational change?"},{"zh":"公共福利中的算法决策能否在效率和程序公平之间取得平衡？","en":"Can algorithmic decisions in public welfare balance efficiency and procedural fairness?"}],"courses":[{"name":"OpenLearn: Society, Politics & Law","url":"https://www.open.edu/openlearn/society/free-courses"},{"name":"Our World in Data","url":"https://ourworldindata.org/"},{"name":"Coursera: Methods and Statistics in Social Sciences","url":"https://www.coursera.org/specializations/social-science"},{"name":"OpenLearn: Society, Politics and Law","url":"https://www.open.edu/openlearn/society-politics-law"}],"books":[{"zh":"The Sociological Imagination — C. Wright Mills","en":"The Sociological Imagination — C. Wright Mills"},{"zh":"Factfulness — Hans Rosling（阅读时同时核查其论证）","en":"Factfulness — Hans Rosling (read alongside critiques of its arguments)"},{"zh":"Bowling Alone — Robert D. Putnam","en":"Bowling Alone — Robert D. Putnam"},{"zh":"Evicted — Matthew Desmond","en":"Evicted — Matthew Desmond"}],"summer":[{"name":"Cambridge Social Sciences Subject Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"University-run social research or public-policy programmes","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"}],"ceiling":98,"portfolio":false},{"id":"ba","math":25,"weights":{"fm":20,"physics":6,"chemistry":3,"economics":22,"biology":2,"psychology":9,"business":17},"essential":[],"recommended":["fm","economics"],"synergies":[[["fm","economics"],8],[["economics","business"],4],[["psychology","business"],3]],"note":{"zh":"商业分析位于数学、数据和商业决策的交界。数学与Further Mathematics支撑模型，Economics/Business帮助理解决策情境，但不能只会做图表。","en":"Business Analytics sits between mathematics, data and business decisions. Mathematics and Further Mathematics support models, while Economics and Business provide decision context. Producing dashboards alone is not enough."},"study":[{"zh":"补概率、统计、回归、优化和数据可视化。","en":"Strengthen probability, statistics, regression, optimisation and data visualisation."},{"zh":"每个指标都问：谁定义、用于什么决策、会不会诱导错误行为。","en":"For every metric, ask who defined it, which decision it supports and whether it creates perverse incentives."},{"zh":"练习把分析结论写成可执行建议，并说明不确定性。","en":"Turn analysis into actionable recommendations while communicating uncertainty."}],"epq":[{"zh":"促销是否真正带来增量销售，还是只是提前了购买？","en":"Do promotions create incremental sales or merely shift purchases earlier?"},{"zh":"客户流失模型在不同群体上的误差是否一致？","en":"Are churn-model errors consistent across customer groups?"},{"zh":"A/B测试中的短期点击提升，能否预测长期用户价值？","en":"Can short-term click gains in A/B tests predict long-term user value?"},{"zh":"管理者看到不同形式的经营看板时，决策会发生怎样的变化？","en":"How do different dashboard designs change managerial decisions?"}],"courses":[{"name":"Coursera: Data Science","url":"https://www.coursera.org/browse/data-science"},{"name":"MIT OCW: Principles of Microeconomics","url":"https://ocw.mit.edu/courses/14-01sc-principles-of-microeconomics-fall-2011/"},{"name":"Wharton / Coursera: Business Analytics Specialization","url":"https://www.coursera.org/specializations/business-analytics"},{"name":"Google Data Analytics Professional Certificate","url":"https://www.coursera.org/professional-certificates/google-data-analytics"}],"books":[{"zh":"Competing on Analytics — Thomas Davenport & Jeanne Harris","en":"Competing on Analytics — Thomas Davenport & Jeanne Harris"},{"zh":"How to Measure Anything — Douglas Hubbard","en":"How to Measure Anything — Douglas Hubbard"},{"zh":"Data Science for Business — Foster Provost & Tom Fawcett","en":"Data Science for Business — Foster Provost & Tom Fawcett"},{"zh":"Storytelling with Data — Cole Nussbaumer Knaflic","en":"Storytelling with Data — Cole Nussbaumer Knaflic"}],"summer":[{"name":"Cambridge Economics/Mathematics Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"University-run business analytics, data or operations programmes","url":"https://www.ox.ac.uk/admissions/undergraduate/supercurricular-hub"}],"ceiling":98,"portfolio":false},{"id":"bism","math":17,"weights":{"fm":11,"physics":7,"chemistry":2,"economics":15,"biology":1,"psychology":8,"business":22},"essential":[],"recommended":["business","economics"],"synergies":[[["business","economics"],5],[["business","psychology"],4],[["fm","business"],3]],"note":{"zh":"商业信息系统管理连接业务流程、数据、系统实施和组织变化。Business有帮助，但还要主动补技术与分析。","en":"Business Information Systems Management is not simply business plus a little IT. It combines business processes, data, system implementation and organisational change. Business is useful, but technical and analytical preparation must be added."},"study":[{"zh":"学习流程建模、数据库基础、系统需求和项目管理。","en":"Learn process modelling, database basics, systems requirements and project management."},{"zh":"练习把用户抱怨翻译成可验证的系统需求。","en":"Translate user complaints into testable system requirements."},{"zh":"理解系统上线为什么会受组织文化、权限和激励影响。","en":"Understand why system implementation is shaped by culture, permissions and incentives."}],"epq":[{"zh":"ERP实施失败更常来自技术问题还是组织问题？","en":"Do ERP implementations fail more often because of technology or organisation?"},{"zh":"学校信息系统中的数据权限应如何设计？","en":"How should data permissions be designed in a school information system?"},{"zh":"ERP项目失败更多来自技术选择，还是组织流程和利益冲突？","en":"Do ERP projects fail mainly because of technology choices, or because of process and stakeholder conflict?"},{"zh":"增加网络安全预算为什么未必能减少人为风险？","en":"Why does a larger cybersecurity budget not necessarily reduce human risk?"}],"courses":[{"name":"OpenLearn: Money & Business","url":"https://www.open.edu/openlearn/money-business/free-courses"},{"name":"MIT OCW: Introduction to CS and Python","url":"https://ocw.mit.edu/courses/6-0001-introduction-to-computer-science-and-programming-in-python-fall-2016/"},{"name":"Coursera: Information Systems Specialization","url":"https://www.coursera.org/specializations/information-systems"},{"name":"MIT OpenCourseWare: Digital Transformation resources","url":"https://ocw.mit.edu/search/?q=digital%20transformation"}],"books":[{"zh":"The Phoenix Project — Gene Kim, Kevin Behr & George Spafford","en":"The Phoenix Project — Gene Kim, Kevin Behr & George Spafford"},{"zh":"Information Systems for Business and Beyond — David Bourgeois et al.","en":"Information Systems for Business and Beyond — David Bourgeois et al."},{"zh":"The Digital Transformation Playbook — David L. Rogers","en":"The Digital Transformation Playbook — David L. Rogers"},{"zh":"Platform Revolution — Geoffrey Parker, Marshall Van Alstyne & Sangeet Choudary","en":"Platform Revolution — Geoffrey Parker, Marshall Van Alstyne & Sangeet Choudary"}],"summer":[{"name":"University-run information systems, digital business or technology programmes","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"},{"name":"Cambridge Computer Science or Management-related Masterclasses","url":"https://www.undergraduate.study.cam.ac.uk/events/masterclasses"}],"ceiling":98,"portfolio":false}];
